import { NextResponse } from "next/server";
import { writeFile } from "fs/promises";
import fs from "fs";
import path from "path";
import nodemailer from "nodemailer";
import pdfjsLib from "pdfjs-dist";

// PDF Worker Configuration (Required for `pdfjs-dist` to work in Node.js)
pdfjsLib.GlobalWorkerOptions.workerSrc = require("pdfjs-dist/build/pdf.worker");

export const config = {
  api: {
    bodyParser: false,
  },
};

// Directory for storing uploaded PDFs
const uploadDir = path.join(process.cwd(), "public/uploads");
if (!fs.existsSync(uploadDir)) {
  fs.mkdirSync(uploadDir, { recursive: true });
}

// Function to save file
const saveFile = async (file: File) => {
  const fileName = `${Date.now()}-${file.name.replace(/\s+/g, "_")}`;
  const filePath = path.join(uploadDir, fileName);

  const bytes = await file.arrayBuffer();
  const buffer = Buffer.from(bytes);

  await writeFile(filePath, buffer);
  return filePath;
};

// Function to extract text using pdfjs-dist
const extractTextFromPDF = async (filePath: string) => {
  const dataBuffer = await fs.promises.readFile(filePath);
  const pdfDoc = await pdfjsLib.getDocument({ data: dataBuffer }).promise;

  let extractedText = "";

  for (let i = 1; i <= pdfDoc.numPages; i++) {
    const page = await pdfDoc.getPage(i);
    const textContent = await page.getTextContent();
    const pageText = textContent.items.map((item: any) => item.str).join(" ");
    extractedText += pageText + "\n";
  }

  return extractedText;
};

// Nodemailer setup
const transporter = nodemailer.createTransport({
  host: process.env.EMAIL_HOST,
  port: Number(process.env.EMAIL_PORT),
  secure: process.env.EMAIL_PORT === "465",
  auth: {
    user: process.env.EMAIL_USER,
    pass: process.env.EMAIL_PASS,
  },
});

export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const email = formData.get("email") as string;
    const file = formData.get("marksheet") as File;

    if (!file) {
      return NextResponse.json(
        { error: "Marksheet file is required" },
        { status: 400 }
      );
    }

    if (!file.name.toLowerCase().endsWith(".pdf")) {
      return NextResponse.json(
        { error: "Marksheet must be a PDF" },
        { status: 400 }
      );
    }

    // Save PDF file
    const savedFilePath = await saveFile(file);
    console.log("File saved at:", savedFilePath);

    // Extract text from PDF
    const extractedText = await extractTextFromPDF(savedFilePath);
    console.log("Extracted Text:", extractedText);

    // Send Email with extracted marks
    await transporter.sendMail({
      from: process.env.EMAIL_USER,
      to: email,
      subject: "Extracted Marks from PDF",
      html: `<p>Your extracted text from the marksheet is:<br> ${extractedText}</p>`,
    });

    return NextResponse.json(
      { message: "File uploaded and analyzed successfully", extractedText },
      { status: 201 }
    );
  } catch (error) {
    console.error("Error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 }
    );
  }
}
